export class PersistentVector<T> {
  private static readonly BRANCH_FACTOR = 32;
  private static readonly SHIFT = 5;
  private static readonly MASK = 0x1f;

  private constructor(
    private readonly root: Node<T>,
    private readonly size: number,
    private readonly tailOffset: number,
    private readonly tail: T[]
  ) {}

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>(new Node<T>([]), 0, 0, []);
  }

  get size(): number {
    return this.size;
  }

  get(i: number): T {
    if (i < 0 || i >= this.size) {
      throw new RangeError(`Index ${i} out of range [0, ${this.size})`);
    }

    if (i >= this.tailOffset) {
      return this.tail[i - this.tailOffset];
    }

    const path = this.getPath(i);
    let node = this.root;
    for (let level = (this.size > 0 ? Math.ceil(Math.log2(this.size)) : 0) - 1; level > 0; level--) {
      const index = (i >> (level * PersistentVector.SHIFT)) & PersistentVector.MASK;
      node = node.children[index] as Node<T>;
    }
    const leafIndex = i & PersistentVector.MASK;
    return (node as LeafNode<T>).values[leafIndex];
  }

  push(value: T): PersistentVector<T> {
    if (this.tail.length < PersistentVector.BRANCH_FACTOR) {
      const newTail = [...this.tail, value];
      return new PersistentVector<T>(this.root, this.size + 1, this.tailOffset, newTail);
    }

    // Tail is full, need to push it into the tree
    const newRoot = this.pushTail(this.root, this.size, this.tail);
    const newTailOffset = this.size + 1;
    return new PersistentVector<T>(newRoot, this.size + 1, newTailOffset, [value]);
  }

  private getPath(i: number): number {
    // Helper to determine the path through the tree
    return i;
  }

  private pushTail(root: Node<T>, size: number, tail: T[]): Node<T> {
    const newTailNode = new LeafNode<T>(tail);
    const newRoot = this.pushNode(root, size, newTailNode);
    return newRoot;
  }

  private pushNode(node: Node<T>, index: number, value: Node<T>): Node<T> {
    const level = this.getLevel(node);
    if (level === 0) {
      // Leaf node, should not happen in this context
      throw new Error("Unexpected leaf node in pushNode");
    }

    const shift = (level - 1) * PersistentVector.SHIFT;
    const mask = PersistentVector.MASK;
    const childIndex = (index >> shift) & mask;

    const newChildren = [...node.children];
    if (childIndex < newChildren.length) {
      newChildren[childIndex] = this.pushNode(newChildren[childIndex] as Node<T>, index, value);
    } else {
      newChildren.push(value);
    }

    return new Node<T>(newChildren);
  }

  private getLevel(node: Node<T>): number {
    if (node instanceof LeafNode) {
      return 0;
    }
    if (node.children.length === 0) {
      return 1;
    }
    return 1 + this.getLevel(node.children[0] as Node<T>);
  }
}

