export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private handlers: {
    [K in keyof TEvents]?: Array<(...args: TEvents[K]) => void>;
  } = {};

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    if (!this.handlers[name]) {
      this.handlers[name] = [];
    }
    this.handlers[name]!.push(handler);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.handlers[name];
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}

class MedianStream {
  private maxHeap: number[] = [];
  private minHeap: number[] = [];
  private count: number = 0;

  add(n: number): void {
    // Add to maxHeap (left half) first
    this.maxHeap.push(n);
    this._bubbleUpMax(this.maxHeap, this.maxHeap.length - 1);

    // Ensure maxHeap's max <= minHeap's min
    if (this.maxHeap.length > 0 && this.minHeap.length > 0 && this.maxHeap[0] > this.minHeap[0]) {
      const maxVal = this.maxHeap[0];
      const minVal = this.minHeap[0];
      this.maxHeap[0] = minVal;
      this.minHeap[0] = maxVal;
      this._bubbleDownMax(this.maxHeap, 0);
      this._bubbleDownMin(this.minHeap, 0);
    }

    // Balance sizes: maxHeap can have at most one more element than minHeap
    if (this.maxHeap.length > this.minHeap.length + 1) {
      const val = this.maxHeap[0];
      this.maxHeap[0] = this.maxHeap[this.maxHeap.length - 1];
      this.maxHeap.pop();
      this._bubbleDownMax(this.maxHeap, 0);
      this.minHeap.push(val);
      this._bubbleUpMin(this.minHeap, this.minHeap.length - 1);
    } else if (this.minHeap.length > this.maxHeap.length) {
      const val = this.minHeap[0];
      this.minHeap[0] = this.minHeap[this.minHeap.length - 1];
      this.minHeap.pop();
      this._bubbleDownMin(this.minHeap, 0);
      this.maxHeap.push(val);
      this._bubbleUpMax(this.maxHeap, this.maxHeap.length - 1);
    }

    this.count++;
  }

  median(): number {
    if (this.count === 0) {
      throw new Error("No elements added yet");
    }

    if (this.maxHeap.length > this.minHeap.length) {
      return this.maxHeap[0];
    } else {
      return (this.maxHeap[0] + this.minHeap[0]) / 2;
    }
  }

  // Max-heap helpers (for left half)
  private _bubbleUpMax(heap: number[], index: number): void {
    while (index > 0) {
      const parent = (index - 1) >> 1;
      if (heap[index] > heap[parent]) {
        [heap[index], heap[parent]] = [heap[parent], heap[index]];
        index = parent;
      } else {
        break;
      }
    }
  }

  private _bubbleDownMax(heap: number[], index: number): void {
    const n = heap.length;
    while (true) {
      let largest = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;
      if (left < n && heap[left] > heap[largest]) {
        largest = left;
      }
      if (right < n && heap[right] > heap[largest]) {
        largest = right;
      }
      if (largest !== index) {
        [heap[index], heap[largest]] = [heap[largest], heap[index]];
        index = largest;
      } else {
        break;
      }
    }
  }

  // Min-heap helpers (for right half)
  private _bubbleUpMin(heap: number[], index: number): void {
    while (index > 0) {
      const parent = (index - 1) >> 1;
      if (heap[index] < heap[parent]) {
        [heap[index], heap[parent]] = [heap[parent], heap[index]];
        index = parent;
      } else {
        break;
      }
    }
  }

  private _bubbleDownMin(heap: number[], index: number): void {
    const n = heap.length;
    while (true) {
      let smallest = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;
      if (left < n && heap[left] < heap[smallest]) {
        smallest = left;
      }
      if (right < n && heap[right] < heap[smallest]) {
        smallest = right;
      }
      if (smallest !== index) {
        [heap[index], heap[smallest]] = [heap[smallest], heap[index]];
        index = smallest;
      } else {
        break;
      }
    }
  }
}

